import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

const AddBus = () => {
  const [formData, setFormData] = useState({
    busNumber: '',
    busName: '',
    busType: 'AC Seater',
    totalSeats: 40,
    route: '',
    departureTime: '',
    arrivalTime: '',
    price: 0,
    amenities: [],
    driverName: '',
    driverContact: '',
    driverLicense: '',
    insuranceNumber: '',
    registrationNumber: '',
    description: ''
  });
  const [errors, setErrors] = useState({});
  const navigate = useNavigate();

  const busTypes = ['AC Seater', 'AC Sleeper', 'Non AC Seater', 'Non AC Sleeper', 'Volvo', 'Luxury Coach'];
  const availableAmenities = [
    'WiFi', 'Charging Port', 'Blanket', 'Water Bottle', 'Snacks', 
    'Entertainment', 'Air Conditioning', 'Reclining Seats', 'Reading Light', 
    'Luggage Space', 'Emergency Exit', 'First Aid Kit', 'CCTV', 'GPS Tracking'
  ];

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;

    if (type === 'checkbox') {
      setFormData(prev => ({
        ...prev,
        amenities: checked 
          ? [...prev.amenities, value]
          : prev.amenities.filter(amenity => amenity !== value)
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        [name]: value
      }));
    }
  };

  const validateForm = () => {
    const newErrors = {};

    if (!formData.busNumber) newErrors.busNumber = 'Bus number is required';
    if (!formData.busName) newErrors.busName = 'Bus name is required';
    if (!formData.route) newErrors.route = 'Route is required';
    if (!formData.departureTime) newErrors.departureTime = 'Departure time is required';
    if (!formData.arrivalTime) newErrors.arrivalTime = 'Arrival time is required';
    if (!formData.price || formData.price <= 0) newErrors.price = 'Valid price is required';
    if (!formData.driverName) newErrors.driverName = 'Driver name is required';
    if (!formData.driverContact) newErrors.driverContact = 'Driver contact is required';
    if (!formData.driverLicense) newErrors.driverLicense = 'Driver license is required';
    if (!formData.insuranceNumber) newErrors.insuranceNumber = 'Insurance number is required';
    if (!formData.registrationNumber) newErrors.registrationNumber = 'Registration number is required';

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if (validateForm()) {
      // In a real app, this would make an API call
      console.log('Adding bus:', formData);
      alert('Bus added successfully!');
      navigate('/bus-manager-dashboard');
    }
  };

  const handleRouteSwap = () => {
    const routes = formData.route.split(' → ');
    if (routes.length === 2) {
      setFormData(prev => ({
        ...prev,
        route: `${routes[1]} → ${routes[0]}`
      }));
    }
  };

  return (
    <div className="container">
      <div className="card">
        <h2>Add New Bus</h2>
        <p style={{ color: '#666', marginBottom: '20px' }}>Add a new bus to your fleet</p>

        <form onSubmit={handleSubmit}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' }}>
            <div>
              <h3>Basic Information</h3>

              <div className="form-group">
                <label>Bus Number *</label>
                <input
                  type="text"
                  name="busNumber"
                  value={formData.busNumber}
                  onChange={handleChange}
                  placeholder="e.g., BUS-001"
                />
                {errors.busNumber && <div style={{ color: 'red', fontSize: '12px' }}>{errors.busNumber}</div>}
              </div>

              <div className="form-group">
                <label>Bus Name *</label>
                <input
                  type="text"
                  name="busName"
                  value={formData.busName}
                  onChange={handleChange}
                  placeholder="e.g., Express Travels"
                />
                {errors.busName && <div style={{ color: 'red', fontSize: '12px' }}>{errors.busName}</div>}
              </div>

              <div className="form-group">
                <label>Bus Type *</label>
                <select
                  name="busType"
                  value={formData.busType}
                  onChange={handleChange}
                >
                  {busTypes.map(type => (
                    <option key={type} value={type}>{type}</option>
                  ))}
                </select>
              </div>

              <div className="form-group">
                <label>Total Seats *</label>
                <input
                  type="number"
                  name="totalSeats"
                  value={formData.totalSeats}
                  onChange={handleChange}
                  min="1"
                  max="60"
                />
              </div>

              <div className="form-group">
                <label>Route *</label>
                <div style={{ display: 'flex', gap: '10px', alignItems: 'center' }}>
                  <input
                    type="text"
                    name="route"
                    value={formData.route}
                    onChange={handleChange}
                    placeholder="e.g., New York → Los Angeles"
                    style={{ flex: 1 }}
                  />
                  <button
                    type="button"
                    onClick={handleRouteSwap}
                    style={{
                      background: 'none',
                      border: '1px solid #ddd',
                      borderRadius: '50%',
                      width: '30px',
                      height: '30px',
                      cursor: 'pointer'
                    }}
                  >
                    ⇄
                  </button>
                </div>
                {errors.route && <div style={{ color: 'red', fontSize: '12px' }}>{errors.route}</div>}
              </div>

              <div className="form-group">
                <label>Price per Seat (₹) *</label>
                <input
                  type="number"
                  name="price"
                  value={formData.price}
                  onChange={handleChange}
                  min="0"
                  step="50"
                />
                {errors.price && <div style={{ color: 'red', fontSize: '12px' }}>{errors.price}</div>}
              </div>

              <div className="form-group">
                <label>Description</label>
                <textarea
                  name="description"
                  value={formData.description}
                  onChange={handleChange}
                  rows="3"
                  placeholder="Bus description and special features"
                />
              </div>
            </div>

            <div>
              <h3>Schedule</h3>

              <div className="form-group">
                <label>Departure Time *</label>
                <input
                  type="time"
                  name="departureTime"
                  value={formData.departureTime}
                  onChange={handleChange}
                />
                {errors.departureTime && <div style={{ color: 'red', fontSize: '12px' }}>{errors.departureTime}</div>}
              </div>

              <div className="form-group">
                <label>Arrival Time *</label>
                <input
                  type="time"
                  name="arrivalTime"
                  value={formData.arrivalTime}
                  onChange={handleChange}
                />
                {errors.arrivalTime && <div style={{ color: 'red', fontSize: '12px' }}>{errors.arrivalTime}</div>}
              </div>

              <h3>Driver Information</h3>

              <div className="form-group">
                <label>Driver Name *</label>
                <input
                  type="text"
                  name="driverName"
                  value={formData.driverName}
                  onChange={handleChange}
                  placeholder="Driver's full name"
                />
                {errors.driverName && <div style={{ color: 'red', fontSize: '12px' }}>{errors.driverName}</div>}
              </div>

              <div className="form-group">
                <label>Driver Contact *</label>
                <input
                  type="tel"
                  name="driverContact"
                  value={formData.driverContact}
                  onChange={handleChange}
                  placeholder="+1-234-567-8900"
                />
                {errors.driverContact && <div style={{ color: 'red', fontSize: '12px' }}>{errors.driverContact}</div>}
              </div>

              <div className="form-group">
                <label>Driver License Number *</label>
                <input
                  type="text"
                  name="driverLicense"
                  value={formData.driverLicense}
                  onChange={handleChange}
                  placeholder="License number"
                />
                {errors.driverLicense && <div style={{ color: 'red', fontSize: '12px' }}>{errors.driverLicense}</div>}
              </div>

              <h3>Vehicle Documents</h3>

              <div className="form-group">
                <label>Insurance Number *</label>
                <input
                  type="text"
                  name="insuranceNumber"
                  value={formData.insuranceNumber}
                  onChange={handleChange}
                  placeholder="Insurance policy number"
                />
                {errors.insuranceNumber && <div style={{ color: 'red', fontSize: '12px' }}>{errors.insuranceNumber}</div>}
              </div>

              <div className="form-group">
                <label>Registration Number *</label>
                <input
                  type="text"
                  name="registrationNumber"
                  value={formData.registrationNumber}
                  onChange={handleChange}
                  placeholder="Vehicle registration number"
                />
                {errors.registrationNumber && <div style={{ color: 'red', fontSize: '12px' }}>{errors.registrationNumber}</div>}
              </div>
            </div>
          </div>

          <div className="form-group">
            <h3>Amenities</h3>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '10px' }}>
              {availableAmenities.map(amenity => (
                <label key={amenity} style={{ display: 'flex', alignItems: 'center', gap: '5px' }}>
                  <input
                    type="checkbox"
                    name="amenities"
                    value={amenity}
                    checked={formData.amenities.includes(amenity)}
                    onChange={handleChange}
                  />
                  {amenity}
                </label>
              ))}
            </div>
          </div>

          <div style={{ display: 'flex', gap: '10px', justifyContent: 'flex-end', marginTop: '30px' }}>
            <button type="button" className="btn btn-secondary" onClick={() => navigate('/bus-manager-dashboard')}>
              Cancel
            </button>
            <button type="submit" className="btn">
              Add Bus
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default AddBus;
